--
-- Table structure for table `oretir_appointments`
--

DROP TABLE IF EXISTS `oretir_appointments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `oretir_appointments` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `reference_number` varchar(20) DEFAULT NULL,
  `member_id` int(10) unsigned DEFAULT NULL,
  `service` varchar(50) NOT NULL,
  `services` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`services`)),
  `preferred_date` date NOT NULL,
  `preferred_time` varchar(10) NOT NULL,
  `vehicle_year` varchar(4) DEFAULT NULL,
  `vehicle_make` varchar(50) DEFAULT NULL,
  `vehicle_model` varchar(50) DEFAULT NULL,
  `vehicle_vin` varchar(17) DEFAULT NULL,
  `tire_size` varchar(30) DEFAULT NULL,
  `tire_preference` enum('new','used','either') DEFAULT NULL,
  `tire_count` tinyint(4) DEFAULT NULL,
  `first_name` varchar(100) NOT NULL,
  `last_name` varchar(100) NOT NULL,
  `phone` varchar(30) NOT NULL,
  `email` varchar(255) NOT NULL,
  `notes` text DEFAULT NULL,
  `service_location` varchar(500) DEFAULT NULL,
  `service_distance_miles` decimal(5,1) DEFAULT NULL,
  `sms_opt_in` tinyint(1) NOT NULL DEFAULT 0,
  `status` enum('new','pending','confirmed','completed','cancelled') NOT NULL DEFAULT 'new',
  `cancel_reason` varchar(500) DEFAULT NULL,
  `reminder_sent` tinyint(1) NOT NULL DEFAULT 0,
  `sms_reminder_sent` tinyint(1) NOT NULL DEFAULT 0,
  `phone_verified` tinyint(1) NOT NULL DEFAULT 0,
  `feedback_sent` tinyint(1) NOT NULL DEFAULT 0,
  `feedback_sent_at` datetime DEFAULT NULL,
  `language` enum('english','spanish') NOT NULL DEFAULT 'english',
  `assigned_employee_id` int(10) unsigned DEFAULT NULL,
  `preferred_employee_id` int(10) unsigned DEFAULT NULL,
  `admin_notes` text DEFAULT NULL,
  `check_in_at` datetime DEFAULT NULL,
  `service_start_at` datetime DEFAULT NULL,
  `service_end_at` datetime DEFAULT NULL,
  `check_out_at` datetime DEFAULT NULL,
  `task_summary` varchar(500) DEFAULT NULL,
  `customer_id` int(10) unsigned DEFAULT NULL,
  `vehicle_id` int(10) unsigned DEFAULT NULL,
  `cancel_token` varchar(64) DEFAULT NULL,
  `cancel_token_expires` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `google_event_id` varchar(255) DEFAULT NULL,
  `calendar_sync_status` enum('pending','success','failed') DEFAULT NULL,
  `calendar_sync_error` text DEFAULT NULL,
  `calendar_synced_at` datetime DEFAULT NULL,
  `review_request_sent` tinyint(1) DEFAULT 0,
  `utm_source` varchar(100) DEFAULT NULL,
  `utm_medium` varchar(100) DEFAULT NULL,
  `utm_campaign` varchar(100) DEFAULT NULL,
  `utm_content` varchar(100) DEFAULT NULL,
  `referral_code` varchar(10) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_cancel_token` (`cancel_token`),
  UNIQUE KEY `idx_reference_number` (`reference_number`),
  KEY `idx_status` (`status`),
  KEY `idx_date` (`preferred_date`),
  KEY `idx_employee` (`assigned_employee_id`),
  KEY `idx_appointments_reminder` (`preferred_date`,`status`,`reminder_sent`),
  KEY `idx_customer` (`customer_id`),
  KEY `idx_vehicle` (`vehicle_id`),
  KEY `idx_member_id` (`member_id`),
  CONSTRAINT `fk_appointment_member` FOREIGN KEY (`member_id`) REFERENCES `members` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_appt_employee` FOREIGN KEY (`assigned_employee_id`) REFERENCES `oretir_employees` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=45 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

