INSERT INTO `oretir_promotions` VALUES (1,'banner','Spring Tire Sale — Save 15% on All Tire Installations!','¡Venta de Llantas de Primavera — Ahorre 15% en Todas las Instalaciones!','Get ready for spring with new tires. 15% off installation on all tires through March 31st.','Prepárese para la primavera con llantas nuevas. 15% de descuento en instalación hasta el 31 de marzo.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Book Now','Reserve Ahora','/book-appointment/','#f59e0b','#000000','SPRING SALE',NULL,NULL,0,'2026-03-01 00:00:00','2026-03-31 23:59:59',0,'2026-02-27 19:04:55','2026-03-20 18:46:48'),(2,'exit_intent','Before You Go…','Antes de Irte…','Enter your email and we will send you a coupon for a complimentary inspection on your next visit.','Ingresa tu correo y te enviaremos un cupon para una inspeccion gratuita en tu proxima visita.','Get a FREE 21-Point Vehicle Health Check','Obten una Inspeccion de 21 Puntos GRATIS','your@email.com','tu@correo.com','Check your email! Your coupon is on its way.','Revisa tu correo! Tu cupon esta en camino.','Something went wrong. Please try again.','Algo salio mal. Intenta de nuevo.','No spam. Unsubscribe anytime.','Sin spam. Cancela cuando quieras.','🔍','Send My Free Coupon','Enviar Mi Cupon Gratis','/api/subscribe.php','#f59e0b','#000000',NULL,NULL,NULL,0,NULL,NULL,0,'2026-03-04 02:25:01','2026-03-20 18:46:48'),(3,'banner','Free Coupon — $25 Off Your First Service!','Cupón Gratis — $25 de Descuento en Tu Primer Servicio!','New to Oregon Tires? Welcome! Enjoy $25 off any service over $75. Show this coupon at checkout or mention it when you book online. One per customer, cannot be combined with other offers.','¿Nuevo en Oregon Tires? ¡Bienvenido! Disfruta $25 de descuento en cualquier servicio mayor a $75. Muestra este cupón al pagar o menciónalo cuando reserves en línea. Uno por cliente, no se puede combinar con otras ofertas.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Book & Save $25','Reserva y Ahorra $25','/book-appointment/','#059669','#ffffff','FREE COUPON','CUPÓN GRATIS',NULL,0,NULL,NULL,10,'2026-03-20 16:03:09','2026-03-20 16:03:09'),(4,'banner','Spring Sale — 15% Off All Services!','Venta de Primavera — 15% de Descuento en Todos los Servicios!','Spring is here and your vehicle needs attention! Get 15% off any service this season — tire installation, brakes, oil changes, alignment, and more. Book online today and save.','¡La primavera llegó y tu vehículo necesita atención! Obtén 15% de descuento en cualquier servicio esta temporada — instalación de llantas, frenos, cambios de aceite, alineación y más. Reserva en línea hoy y ahorra.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Book Now — 15% Off','Reserva Ahora — 15% Desc.','/book-appointment/','#16a34a','#ffffff','SPRING SALE','VENTA DE PRIMAVERA',NULL,0,NULL,NULL,20,'2026-03-20 16:03:09','2026-03-20 16:03:09'),(5,'banner','New Customer Special — Free Inspection + 10% Off','Especial para Nuevos Clientes — Inspección Gratis + 10% de Descuento','First time at Oregon Tires? Get a free 35-point digital vehicle inspection plus 10% off any recommended service. We will show you exactly what your car needs — no pressure, no surprises.','¿Primera vez en Oregon Tires? Obtén una inspección digital de 35 puntos gratis más 10% de descuento en cualquier servicio recomendado. Te mostramos exactamente lo que tu auto necesita — sin presión, sin sorpresas.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Book Free Inspection','Reserva Inspección Gratis','/book-appointment/','#0d9488','#ffffff','NEW CUSTOMER','NUEVO CLIENTE',NULL,0,NULL,NULL,30,'2026-03-20 16:03:09','2026-03-20 16:03:09');
/*!40000 ALTER TABLE `oretir_promotions` ENABLE KEYS */;
UNLOCK TABLES;

