el lado de adentro',NULL,NULL,'[Damian — Mar 22, 2026 2:03am]\nergnhbqeriof´qérhigfóihqergóihqerg\n\n[Damian — Mar 21, 2026 8:40pm]\neadgqergqergqergqergqergqergqergqregqergqergqerg','[Damian — Mar 21, 2026 8:40pm]\nosidhjfiksndf9iuqegf´kjwh\'fiqnegíhqergiqeriqerog´q¿er9hg+qpeorjg0qjieg0grej','2026-03-23','08:15','2026-03-21 20:39:01','2026-03-21 20:39:29','2026-03-21 20:41:41','2026-03-21 20:41:19','2026-03-21 20:36:00','2026-03-22 02:03:44'),(15,'RO-S2R97B58',4,8,31,14,6,'invoiced',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-03-21','08:00','2026-03-22 02:02:29','2026-03-22 02:02:44','2026-03-22 02:03:21','2026-03-22 02:03:26','2026-03-22 02:02:06','2026-03-22 02:03:26');
