INSERT INTO `oretir_services` VALUES (1,'tire-installation','Tire Installation','Instalación de Llantas','Professional tire installation in Portland, OR. Mounting, balancing, and TPMS reset included. Bilingual English & Spanish service.','Instalacion profesional de llantas en Portland, OR. Montaje, balanceo y reinicio de TPMS incluidos. Servicio bilingue.','<p>Oregon Tires Auto Care offers professional tire installation for all vehicle types. Every installation includes mounting, computer-aided balancing, TPMS sensor reset, and a torque-to-spec finish. We work with tires you purchase from us or bring in yourself.</p><p>We carry a wide selection of new and quality used tires from trusted brands. Whether you need all-season, winter, or performance tires, our technicians will help you find the right fit for your vehicle and driving needs.</p>','<p>Oregon Tires Auto Care ofrece instalacion profesional de llantas para todo tipo de vehiculo. Cada instalacion incluye montaje, balanceo por computadora, reinicio del sensor TPMS y torque a especificacion. Trabajamos con llantas compradas con nosotros o que usted traiga.</p><p>Tenemos una amplia seleccion de llantas nuevas y usadas de calidad. Ya sea que necesite llantas para toda temporada, invierno o alto rendimiento, nuestros tecnicos le ayudaran a encontrar la opcion correcta.</p>','&#x1F527;','#3B82F6','bg-blue-100','text-blue-800','dark:bg-blue-900/30','dark:text-blue-300','bg-blue-500','','','tires',1,1,1,1,'',NULL,NULL,NULL,'45-90','2026-03-20 19:06:42','2026-03-21 03:00:42'),(2,'tire-repair','Tire Repair','Reparación de Llantas','Fast tire repair and patching in Portland, OR. Flat tire fix, puncture repair, and tire inspection. Same-day service available. Bilingual English & Spanish service.','Reparacion rapida de llantas y parches en Portland, OR. Reparacion de llantas ponchadas, reparacion de pinchazos e inspeccion de llantas. Servicio el mismo dia disponible. Servicio bilingue.','<p>Oregon Tires Auto Care offers professional tire repair for punctures and slow leaks. We assess every tire for repairability per industry standards, then perform a plug/patch combination from the inside of the tire for a lasting, safe repair.</p><p>If a tire is unrepairable due to sidewall damage, large punctures, or excessive wear, we will honestly let you know and recommend affordable replacement options from our selection of new and quality used tires. Most tire repairs are completed in under 30 minutes.</p>','<p>Oregon Tires Auto Care ofrece reparacion profesional de llantas para pinchazos y fugas lentas. Evaluamos cada llanta para determinar si es reparable segun los estandares de la industria, luego realizamos una combinacion de tapon/parche desde el interior de la llanta para una reparacion duradera y segura.</p><p>Si una llanta no es reparable debido a dano en la pared lateral, pinchazos grandes o desgaste excesivo, se lo informaremos honestamente y recomendaremos opciones de reemplazo accesibles de nuestra seleccion de llantas nuevas y usadas de calidad. La mayoria de las reparaciones de llantas se completan en menos de 30 minutos.</p>','&#x1F6DE;','#60A5FA','bg-blue-100','text-blue-700','dark:bg-blue-900/30','dark:text-blue-300','bg-blue-400','','','tires',1,1,1,2,'',NULL,NULL,NULL,'20-40','2026-03-20 19:06:42','2026-03-21 03:00:42'),(3,'wheel-alignment','Wheel Alignment','Alineación de Ruedas','Computerized wheel alignment for all vehicles in Portland, OR. Corrects camber, caster, and toe for even tire wear and straight driving. Bilingual service.','Alineacion de ruedas computarizada para todos los vehiculos en Portland, OR. Corrige camber, caster y convergencia para desgaste uniforme y conduccion recta. Servicio bilingue.','<p>Oregon Tires Auto Care offers precision 4-wheel alignment using state-of-the-art computerized equipment. We correct camber, caster, and toe angles to manufacturer specifications, ensuring even tire wear and straight, predictable handling.</p><p>Proper alignment extends the life of your tires, improves fuel efficiency, and makes your vehicle safer to drive. We recommend an alignment check every 12 months, after hitting a pothole or curb, or whenever you install new tires.</p>','<p>Oregon Tires Auto Care ofrece alineacion de precision de 4 ruedas usando equipo computarizado de ultima generacion. Corregimos los angulos de camber, caster y convergencia a las especificaciones del fabricante, asegurando un desgaste uniforme de las llantas y un manejo recto y predecible.</p><p>Una alineacion adecuada extiende la vida de sus llantas, mejora la eficiencia de combustible y hace que su vehiculo sea mas seguro de conducir. Recomendamos una revision de alineacion cada 12 meses, despues de golpear un bache o banqueta, o cuando instale llantas nuevas.</p>','&#x2699;','#8B5CF6','bg-purple-100','text-purple-800','dark:bg-purple-900/30','dark:text-purple-300','bg-purple-500','','','tires',1,1,1,3,'',NULL,NULL,NULL,'45-60','2026-03-20 19:06:42','2026-03-21 03:00:42'),(4,'brake-service','Brake Service','Servicio de Frenos','Complete brake service in Portland, OR. Pad replacement, rotor resurfacing, and brake fluid flush. Bilingual English & Spanish service.','Servicio completo de frenos en Portland, OR. Reemplazo de pastillas, rectificacion de rotores y cambio de liquido de frenos. Servicio bilingue.','<p>Oregon Tires Auto Care provides comprehensive brake inspection and repair services for all vehicle types. Our services include brake pad and shoe replacement, rotor resurfacing or replacement, caliper service, brake fluid flush, and ABS diagnostics.</p><p>Your brakes are your vehicle\'s most critical safety system. Our experienced technicians use quality parts and follow manufacturer specifications to ensure your brakes perform reliably. We provide a detailed inspection report and honest recommendations with every service.</p>','<p>Oregon Tires Auto Care ofrece servicios completos de inspeccion y reparacion de frenos para todo tipo de vehiculo. Nuestros servicios incluyen reemplazo de pastillas y zapatas, rectificacion o reemplazo de rotores, servicio de calibradores, cambio de liquido de frenos y diagnostico de ABS.</p><p>Sus frenos son el sistema de seguridad mas critico de su vehiculo. Nuestros tecnicos experimentados usan piezas de calidad y siguen las especificaciones del fabricante para asegurar que sus frenos funcionen de manera confiable. Proporcionamos un informe detallado de inspeccion y recomendaciones honestas con cada servicio.</p>','&#x1F6D1;','#EF4444','bg-red-100','text-red-800','dark:bg-red-900/30','dark:text-red-300','bg-red-500','','','maintenance',1,1,1,4,'',NULL,NULL,NULL,'60-120','2026-03-20 19:06:42','2026-03-20 19:06:42'),(5,'oil-change','Oil Change','Cambio de Aceite','Conventional and synthetic oil changes in Portland, OR. Includes filter replacement and multi-point inspection. Bilingual English & Spanish service.','Cambios de aceite convencional y sintetico en Portland, OR. Incluye reemplazo de filtro e inspeccion multipunto. Servicio bilingue.','<p>Oregon Tires Auto Care provides full oil change services including conventional, synthetic blend, and full synthetic options. Every oil change includes a new oil filter, fluid top-offs, and a complimentary multi-point vehicle inspection to catch potential issues early.</p><p>Regular oil changes are the single most important maintenance you can do for your engine. Our technicians use quality oils and filters to keep your engine running smoothly and extend its lifespan. We service all makes and models.</p>','<p>Oregon Tires Auto Care ofrece servicios completos de cambio de aceite incluyendo convencional, mezcla sintetica y sintetico completo. Cada cambio de aceite incluye un filtro nuevo, relleno de fluidos y una inspeccion multipunto cortesia para detectar problemas potenciales temprano.</p><p>Los cambios de aceite regulares son el mantenimiento mas importante que puede hacer para su motor. Nuestros tecnicos usan aceites y filtros de calidad para mantener su motor funcionando sin problemas y extender su vida util. Atendemos todas las marcas y modelos.</p>','&#x1F6E2;','#F97316','bg-orange-100','text-orange-800','dark:bg-orange-900/30','dark:text-orange-300','bg-orange-500','','','maintenance',1,1,1,5,'',NULL,NULL,NULL,'20-30','2026-03-20 19:06:42','2026-03-20 19:06:42'),(6,'engine-diagnostics','Engine Diagnostics','Diagnóstico de Motor','Advanced engine diagnostic services in Portland, OR. Check engine light diagnosis, OBD-II scanning, and performance testing. Bilingual English & Spanish service.','Servicios avanzados de diagnostico de motor en Portland, OR. Diagnostico de luz de motor, escaneo OBD-II y pruebas de rendimiento. Servicio bilingue.','<p>Oregon Tires Auto Care provides full computer diagnostic services using professional OBD-II scanning equipment. We identify the causes behind check engine lights, engine misfires, sensor failures, emissions issues, and overall performance problems.</p><p>After the diagnostic scan, we provide a detailed report with clear explanations of what we found and our repair recommendations with upfront pricing. We never pressure you into repairs — just honest information so you can make the best decision for your vehicle.</p>','<p>Oregon Tires Auto Care ofrece servicios completos de diagnostico por computadora usando equipo profesional de escaneo OBD-II. Identificamos las causas detras de las luces de motor, fallas de encendido, fallas de sensores, problemas de emisiones y problemas generales de rendimiento.</p><p>Despues del escaneo diagnostico, proporcionamos un informe detallado con explicaciones claras de lo que encontramos y nuestras recomendaciones de reparacion con precios transparentes. Nunca lo presionamos para hacer reparaciones — solo informacion honesta para que pueda tomar la mejor decision para su vehiculo.</p>','&#x1F50D;','#06B6D4','bg-cyan-100','text-cyan-800','dark:bg-cyan-900/30','dark:text-cyan-300','bg-cyan-500','','','specialized',1,1,1,6,'',NULL,NULL,NULL,'30-60','2026-03-20 19:06:42','2026-03-21 03:00:42'),(7,'suspension-repair','Suspension Repair','Reparación de Suspensión','Professional suspension repair in Portland, OR. Shocks, struts, control arms, ball joints, and steering components. Bilingual English & Spanish service.','Reparacion profesional de suspension en Portland, OR. Amortiguadores, puntales, brazos de control, rotulas y componentes de direccion. Servicio bilingue.','<p>Oregon Tires Auto Care provides complete suspension diagnosis and repair for all vehicle types. Our services cover shocks, struts, control arms, ball joints, tie rod ends, sway bar links, and steering rack service to restore your vehicle\'s smooth ride and handling.</p><p>A worn suspension affects your vehicle\'s ride comfort, handling, braking distance, and tire wear. Our technicians thoroughly inspect your suspension system, explain what we find in plain language, and recommend only the repairs you actually need.</p>','<p>Oregon Tires Auto Care ofrece diagnostico y reparacion completa de suspension para todo tipo de vehiculo. Nuestros servicios cubren amortiguadores, puntales, brazos de control, rotulas, terminales de barra, enlaces de barra estabilizadora y servicio de cremallera de direccion para restaurar la conduccion suave y el manejo de su vehiculo.</p><p>Una suspension desgastada afecta la comodidad de conduccion, el manejo, la distancia de frenado y el desgaste de las llantas. Nuestros tecnicos inspeccionan minuciosamente su sistema de suspension, explican lo que encuentran en lenguaje sencillo y recomiendan solo las reparaciones que realmente necesita.</p>','&#x1F699;','#8B5CF6','bg-purple-100','text-purple-800','dark:bg-purple-900/30','dark:text-purple-300','bg-purple-500','','','specialized',1,1,1,7,'',NULL,NULL,NULL,'120-240','2026-03-20 19:06:42','2026-03-21 03:00:42'),(8,'roadside-assistance','Roadside Assistance','Asistencia en Carretera','Emergency roadside assistance in Portland, OR. Flat tire change, jump start, lockout help, and towing coordination. Bilingual English & Spanish service.','Asistencia en carretera de emergencia en Portland, OR. Cambio de llanta ponchada, arranque con cables, ayuda con cerraduras y coordinacion de grua. Servicio bilingue.','<p>Stranded on the road? Oregon Tires Auto Care provides emergency roadside assistance throughout the Portland metro area. Whether you have a flat tire, a dead battery, or you\'re locked out of your vehicle, our experienced team is ready to help you get back on the road quickly and safely.</p><p>We offer flat tire changes, jump starts, lockout assistance, and can coordinate towing to our shop or a location of your choice. Our bilingual team is available during business hours to ensure clear communication and fast response.</p>','<p>¿Varado en la carretera? Oregon Tires Auto Care ofrece asistencia en carretera de emergencia en toda el area metropolitana de Portland. Ya sea que tenga una llanta ponchada, una bateria muerta o este bloqueado fuera de su vehiculo, nuestro equipo experimentado esta listo para ayudarlo a volver a la carretera de manera rapida y segura.</p><p>Ofrecemos cambio de llantas ponchadas, arranque con cables, asistencia con cerraduras y coordinamos servicio de grua a nuestro taller o al lugar de su eleccion. Nuestro equipo bilingue esta disponible durante el horario de atencion.</p>','&#x1F6A8;','#F43F5E','bg-rose-100','text-rose-800','dark:bg-rose-900/30','dark:text-rose-300','bg-rose-500','','','specialized',1,1,1,8,'','\n  <!-- ═══ Pricing Estimator ═══ -->\n  <section class=\"py-12 bg-gray-50 dark:bg-gray-800/50\">\n    <div class=\"max-w-2xl mx-auto px-4 sm:px-6\">\n      <h2 class=\"text-2xl font-bold text-gray-900 dark:text-white mb-2 text-center\">\n        <span data-t=\"estimator_title\">Get an Estimate</span>\n      </h2>\n      <p class=\"text-gray-600 dark:text-gray-400 mb-6 text-center\">\n        <span data-t=\"estimator_subtitle\">Select your service and location for an instant estimate.</span>\n      </p>\n      <div id=\"roadside-estimator\" data-price-base=\"75\" data-price-zone=\"15\"></div>\n    </div>\n  </section>','\n<script src=\"/assets/js/roadside-estimator.js\"></script>\n<script>\n  document.addEventListener(\"DOMContentLoaded\", function() {\n    RoadsideEstimator.init(\"roadside-estimator\");\n  });\n</script>','\n      estimator_title: \'Obtener Estimado\',\n      estimator_subtitle: \'Seleccione su servicio y ubicación para un estimado inmediato.\',','30-60','2026-03-20 19:06:42','2026-03-20 19:06:42'),(9,'mobile-service','Mobile Service','Servicio Móvil','Mobile tire and auto service in Portland, OR. We come to your home, office, or roadside location. Bilingual English & Spanish service.','Servicio movil de llantas y auto en Portland, OR. Vamos a su casa, oficina o ubicacion en la carretera. Servicio bilingue ingles y espanol.','<p>Oregon Tires Auto Care brings professional tire and auto service directly to you anywhere in the Portland metro area. Whether you are at home, at work, or stranded on the road, our fully equipped mobile unit can handle tire installation, tire repair, flat fixes, and basic maintenance on-site.</p><p>Our mobile service saves you time and hassle — no need to drive to the shop or wait for a tow truck. We carry a full selection of new and quality used tires on our mobile unit, along with professional mounting and balancing equipment. Same-day service is available for most requests.</p>','<p>Oregon Tires Auto Care lleva servicio profesional de llantas y auto directamente a usted en cualquier lugar del area metropolitana de Portland. Ya sea que este en casa, en el trabajo o varado en la carretera, nuestra unidad movil completamente equipada puede manejar instalacion de llantas, reparacion de llantas, arreglo de ponchadas y mantenimiento basico en el lugar.</p><p>Nuestro servicio movil le ahorra tiempo y molestias — no necesita manejar al taller ni esperar una grua. Llevamos una seleccion completa de llantas nuevas y usadas de calidad en nuestra unidad movil, junto con equipo profesional de montaje y balanceo. Servicio el mismo dia esta disponible para la mayoria de las solicitudes.</p>','&#x1F69A;','#EAB308','bg-yellow-100','text-yellow-800','dark:bg-yellow-900/30','dark:text-yellow-300','bg-yellow-500','','','specialized',1,1,1,9,'','\n  <!-- ═══ Service Coverage ═══ -->\n  <section class=\"py-12\">\n    <div class=\"max-w-4xl mx-auto px-4 sm:px-6\">\n      <h2 class=\"text-2xl font-bold text-gray-900 dark:text-white mb-6 text-center\">\n        <span data-t=\"coverage_title\">Service Coverage Area</span>\n      </h2>\n      <div class=\"grid grid-cols-1 md:grid-cols-2 gap-6\">\n        <div class=\"bg-green-50 dark:bg-green-900/20 rounded-xl p-6\">\n          <h3 class=\"font-semibold text-green-800 dark:text-green-400 mb-3\">\n            <span data-t=\"coverage_range\">Coverage Range</span>\n          </h3>\n          <ul class=\"space-y-2 text-gray-700 dark:text-gray-300 text-sm\">\n            <li class=\"flex items-start gap-2\">\n              <svg class=\"w-5 h-5 text-green-600 mt-0.5 shrink-0\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M5 13l4 4L19 7\"/></svg>\n              <span data-t=\"coverage_15mi\">Service within 15 miles of our shop</span>\n            </li>\n            <li class=\"flex items-start gap-2\">\n              <svg class=\"w-5 h-5 text-green-600 mt-0.5 shrink-0\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M5 13l4 4L19 7\"/></svg>\n              <span data-t=\"coverage_trip_fee\">A trip fee may apply based on distance</span>\n            </li>\n            <li class=\"flex items-start gap-2\">\n              <svg class=\"w-5 h-5 text-green-600 mt-0.5 shrink-0\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M5 13l4 4L19 7\"/></svg>\n              <span data-t=\"coverage_confirm\">We confirm availability and total cost before dispatching</span>\n            </li>\n          </ul>\n        </div>\n        <div class=\"bg-white dark:bg-gray-800 rounded-xl p-6 shadow-sm\">\n          <h3 class=\"font-semibold text-gray-900 dark:text-white mb-3\">\n            <span data-t=\"coverage_areas\">Areas We Serve</span>\n          </h3>\n          <div class=\"grid grid-cols-2 gap-2 text-sm text-gray-600 dark:text-gray-400\">\n            <span>SE Portland</span><span>Clackamas</span>\n            <span>Happy Valley</span><span>Milwaukie</span>\n            <span>Lents</span><span>Woodstock</span>\n            <span>Foster-Powell</span><span>Mt. Scott</span>\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>',NULL,'\n      coverage_title: \'Área de Cobertura de Servicio\',\n      coverage_range: \'Rango de Cobertura\',\n      coverage_15mi: \'Servicio dentro de 15 millas de nuestro taller\',\n      coverage_trip_fee: \'Se puede aplicar una tarifa de viaje según la distancia\',\n      coverage_confirm: \'Confirmamos disponibilidad y costo total antes de enviar\',\n      coverage_areas: \'Áreas que Servimos\',','60-120','2026-03-20 19:06:42','2026-03-21 03:00:42'),(10,'tuneup','Tune-Up','Afinacion','Engine tune-up service.','Servicio de afinacion de motor.','','','&#x2699;','#10B981','bg-emerald-100','text-emerald-800','dark:bg-emerald-900/30','dark:text-emerald-300','bg-emerald-500','','','maintenance',1,0,1,10,'',NULL,NULL,NULL,'30-60','2026-03-20 19:06:42','2026-03-20 19:06:42'),(11,'mechanical-inspection','Mechanical Inspection','Inspeccion Mecanica','Full vehicle mechanical inspection.','Inspeccion mecanica completa del vehiculo.','','','&#x1F50D;','#06B6D4','bg-cyan-100','text-cyan-800','dark:bg-cyan-900/30','dark:text-cyan-300','bg-cyan-500','','','specialized',1,0,1,11,'',NULL,NULL,NULL,'30-60','2026-03-20 19:06:42','2026-03-20 19:06:42'),(12,'other','Other','Otro','Other services.','Otros servicios.','','','&#x2753;','#9CA3AF','bg-gray-100','text-gray-700','dark:bg-gray-700','dark:text-gray-300','bg-gray-400','','','specialized',1,0,1,99,'',NULL,NULL,NULL,'','2026-03-20 19:06:42','2026-03-20 19:06:42'),(13,'fleet-services','Fleet Services','Servicios de Flota','Volume pricing and priority service for commercial fleets.','Precios por volumen y servicio prioritario para flotas comerciales.','','','????','#6366F1','bg-indigo-100','text-indigo-800','dark:bg-indigo-900/30','dark:text-indigo-300','bg-indigo-500','Custom pricing','Precios personalizados','specialized',1,1,1,9,'',NULL,NULL,NULL,'','2026-03-21 03:00:42','2026-03-21 03:00:42');
