INSERT INTO `oretir_site_settings` VALUES (1,'phone','(503) 367-9714','(503) 367-9714','2026-02-17 01:12:36'),(2,'email','oregontirespdx@gmail.com','oregontirespdx@gmail.com','2026-02-17 01:12:36'),(3,'address','8536 SE 82nd Ave, Portland, OR 97266','8536 SE 82nd Ave, Portland, OR 97266','2026-02-17 01:12:36'),(4,'hours_weekday','Mon-Sat 7AM-7PM','Lun-Sab 7AM-7PM','2026-02-17 01:12:36'),(5,'hours_sunday','Sunday: Closed','Domingo: Cerrado','2026-02-17 01:12:36'),(6,'rating_value','4.8','4.8','2026-02-17 01:12:36'),(7,'review_count','979','150+','2026-03-18 06:00:07'),(8,'email_tpl_welcome_subject','Set Up Your Password — Oregon Tires Admin','Configura tu Contraseña — Oregon Tires Admin','2026-02-18 02:27:47'),(9,'email_tpl_welcome_greeting','Welcome, {{name}}!','¡Bienvenido/a, {{name}}!','2026-02-18 02:27:47'),(10,'email_tpl_welcome_button','Set Up My Password','Configurar Mi Contraseña','2026-02-18 02:27:47'),(13,'email_tpl_welcome_body','You\'ve been invited to the <strong style=\"color:#15803d;\">Oregon Tires Auto Care Admin Panel</strong> as <strong>{{role}}</strong>. To activate your account, set up your password by clicking the button below.','Has sido invitado/a al <strong style=\"color:#15803d;\">Panel de Administración de Oregon Tires Auto Care</strong> como <strong>{{role}}</strong>. Para activar tu cuenta, configura tu contraseña haciendo clic en el botón de abajo.','2026-02-18 02:28:38'),(15,'email_tpl_welcome_footer','This link expires in <strong>{{expiry_days}} days</strong>. If you didn\'t request this account, you can safely ignore this email.','Este enlace expira en <strong>{{expiry_days}} días</strong>. Si no solicitaste esta cuenta, puedes ignorar este correo de forma segura.','2026-02-18 02:28:38'),(16,'email_tpl_reset_subject','Reset Your Password — Oregon Tires Admin','Restablece tu Contraseña — Oregon Tires Admin','2026-02-18 02:28:38'),(17,'email_tpl_reset_greeting','Hello, {{name}}','Hola, {{name}}','2026-02-18 02:28:38'),(18,'email_tpl_reset_body','We received a request to reset your password for the <strong style=\"color:#15803d;\">Oregon Tires Auto Care Admin Panel</strong>. Click the button below to choose a new password.','Recibimos una solicitud para restablecer tu contraseña del <strong style=\"color:#15803d;\">Panel de Administración de Oregon Tires Auto Care</strong>. Haz clic en el botón de abajo para elegir una nueva contraseña.','2026-02-18 02:28:38'),(19,'email_tpl_reset_button','Reset My Password','Restablecer Mi Contraseña','2026-02-18 02:28:38'),(20,'email_tpl_reset_footer','This link expires in <strong>1 hour</strong>. If you didn\'t request this, you can safely ignore this email.','Este enlace expira en <strong>1 hora</strong>. Si no solicitaste esto, puedes ignorar este correo de forma segura.','2026-02-18 02:28:38'),(21,'email_tpl_contact_subject','New Contact Message from {{name}}','Nuevo Mensaje de Contacto de {{name}}','2026-02-18 02:28:38'),(22,'email_tpl_contact_greeting','New message received','Nuevo mensaje recibido','2026-02-18 02:28:38'),(23,'email_tpl_contact_body','You have a new contact message from <strong>{{name}}</strong> ({{email}}):<br><br><em>\"{{message}}\"</em>','Tienes un nuevo mensaje de contacto de <strong>{{name}}</strong> ({{email}}):<br><br><em>\"{{message}}\"</em>','2026-02-18 02:28:38'),(24,'email_tpl_contact_button','View in Admin Panel','Ver en el Panel','2026-02-18 02:28:38'),(25,'email_tpl_contact_footer','This is an automated notification from Oregon Tires Auto Care.','Esta es una notificación automática de Oregon Tires Auto Care.','2026-02-18 02:28:38'),(26,'email_tpl_booking_subject','Appointment Requested — Oregon Tires Auto Care','Cita Solicitada — Oregon Tires Auto Care','2026-02-19 07:06:42'),(27,'email_tpl_booking_greeting','Thank you, {{name}}!','¡Gracias, {{name}}!','2026-02-19 07:06:42'),(28,'email_tpl_booking_body','We have received your appointment request for <strong>{{service}}</strong> on <strong>{{date}}</strong> at <strong>{{time}}</strong>.{{vehicle_line}}<br><br>We will contact you shortly to confirm your appointment.','Hemos recibido su solicitud de cita para <strong>{{service}}</strong> el <strong>{{date}}</strong> a las <strong>{{time}}</strong>.{{vehicle_line}}<br><br>Nos comunicaremos con usted pronto para confirmar su cita.','2026-03-03 22:33:32'),(29,'email_tpl_booking_button','Visit Our Website','Visitar Nuestro Sitio','2026-02-19 07:06:42'),(30,'email_tpl_booking_footer','If you need to reschedule, please call us at <strong>(503) 367-9714</strong>.<br>Mon-Sat 7:00 AM - 7:00 PM','Si necesita reprogramar, llamenos al <strong>(503) 367-9714</strong>.<br>Lun-Sab 7:00 AM - 7:00 PM','2026-02-19 07:06:42'),(31,'google_analytics_id','G-CHYMTNB6LH','G-CHYMTNB6LH','2026-02-19 21:49:49'),(32,'email_tpl_inspection_subject','Vehicle Inspection Report — {{ro_number}}','Reporte de Inspección del Vehículo — {{ro_number}}','2026-02-22 16:22:26'),(33,'email_tpl_inspection_greeting','Hello {{name}},','Hola {{name}},','2026-02-22 16:22:26'),(34,'email_tpl_inspection_body','We\'ve completed a digital vehicle inspection on your <strong>{{vehicle}}</strong>. Our technician has documented the condition of key components with photos and ratings. Click below to view your full inspection report.','Hemos completado una inspección digital de su <strong>{{vehicle}}</strong>. Nuestro técnico ha documentado el estado de los componentes clave con fotos y calificaciones. Haga clic abajo para ver su reporte completo de inspección.','2026-02-22 16:22:26'),(35,'email_tpl_inspection_button','View Inspection Report','Ver Reporte de Inspección','2026-02-22 16:22:26'),(36,'email_tpl_inspection_footer','This report is available for 90 days. If you have questions, call us at (503) 367-9714.','Este reporte está disponible por 90 días. Si tiene preguntas, llámenos al (503) 367-9714.','2026-02-22 16:22:26'),(37,'email_tpl_estimate_subject','Estimate Ready for Approval — {{ro_number}}','Presupuesto Listo para Aprobación — {{ro_number}}','2026-02-22 16:22:26'),(38,'email_tpl_estimate_greeting','Hello {{name}},','Hola {{name}},','2026-02-22 16:22:26'),(39,'email_tpl_estimate_body','We\'ve prepared an estimate for your <strong>{{vehicle}}</strong> totaling <strong>{{total}}</strong>. You can review each recommended service and approve the ones you\'d like us to perform. Click below to review and approve your estimate.','Hemos preparado un presupuesto para su <strong>{{vehicle}}</strong> con un total de <strong>{{total}}</strong>. Puede revisar cada servicio recomendado y aprobar los que desee que realicemos. Haga clic abajo para revisar y aprobar su presupuesto.','2026-02-22 16:22:26'),(40,'email_tpl_estimate_button','Review & Approve Estimate','Revisar y Aprobar Presupuesto','2026-02-22 16:22:26'),(41,'email_tpl_estimate_footer','This estimate is valid for 30 days. Questions? Call us at (503) 367-9714.','Este presupuesto es válido por 30 días. ¿Preguntas? Llámenos al (503) 367-9714.','2026-02-22 16:22:26'),(42,'email_tpl_approval_subject','Estimate Approved — Work Starting on {{vehicle}}','Presupuesto Aprobado — Trabajo Comenzando en {{vehicle}}','2026-02-22 16:22:26'),(43,'email_tpl_approval_greeting','Thank you, {{name}}!','¡Gracias, {{name}}!','2026-02-22 16:22:26'),(44,'email_tpl_approval_body','You\'ve approved services for your <strong>{{vehicle}}</strong>. Our team will begin work shortly. We\'ll notify you as soon as your vehicle is ready for pickup.','Ha aprobado los servicios para su <strong>{{vehicle}}</strong>. Nuestro equipo comenzará el trabajo pronto. Le notificaremos tan pronto como su vehículo esté listo para recoger.','2026-02-22 16:22:26'),(45,'email_tpl_approval_button','View Approved Services','Ver Servicios Aprobados','2026-02-22 16:22:26'),(46,'email_tpl_approval_footer','Estimated completion: {{date}}. Questions? Call us at (503) 367-9714.','Finalización estimada: {{date}}. ¿Preguntas? Llámenos al (503) 367-9714.','2026-02-22 16:22:26'),(47,'email_tpl_vehicle_ready_subject','Your Vehicle is Ready! — {{ro_number}}','¡Su Vehículo Está Listo! — {{ro_number}}','2026-02-22 16:22:26'),(48,'email_tpl_vehicle_ready_greeting','Great news, {{name}}!','¡Buenas noticias, {{name}}!','2026-02-22 16:22:26'),(49,'email_tpl_vehicle_ready_body','Your <strong>{{vehicle}}</strong> is ready for pickup at Oregon Tires Auto Care. All approved services have been completed. We\'re open Mon-Sat 7AM-7PM.','Su <strong>{{vehicle}}</strong> está listo para recoger en Oregon Tires Auto Care. Todos los servicios aprobados han sido completados. Estamos abiertos Lun-Sab 7AM-7PM.','2026-02-22 16:22:26'),(50,'email_tpl_vehicle_ready_button','Get Directions','Obtener Direcciones','2026-02-22 16:22:26'),(51,'email_tpl_vehicle_ready_footer','Thank you for choosing Oregon Tires Auto Care! We appreciate your business.','¡Gracias por elegir Oregon Tires Auto Care! Apreciamos su negocio.','2026-02-22 16:22:26'),(52,'email_tpl_subscriber_welcome_subject','Welcome to Oregon Tires! Here\'s Your Free Inspection Coupon','Bienvenido a Oregon Tires! Aquí está su cupón de inspección gratuita','2026-02-27 17:31:15'),(53,'email_tpl_subscriber_welcome_greeting','Welcome to Oregon Tires Auto Care!','¡Bienvenido a Oregon Tires Auto Care!','2026-02-27 17:31:15'),(54,'email_tpl_subscriber_welcome_body','Thank you for subscribing to our newsletter! As a thank you, here\'s your exclusive coupon for a FREE 21-point vehicle inspection:\n\nUse code: FREEINSPECT\n\nThis inspection covers brakes, tires, fluids, belts, battery, and more. Just mention this code when you book your appointment or show this email at drop-off.\n\nAs a subscriber, you\'ll also get:\n• Early access to seasonal tire deals\n• Maintenance reminders and tips\n• Exclusive subscriber-only discounts','Gracias por suscribirse a nuestro boletín. Como agradecimiento, aquí tiene su cupón exclusivo para una inspección vehicular GRATUITA de 21 puntos:\n\nUse el código: FREEINSPECT\n\nEsta inspección cubre frenos, llantas, fluidos, correas, batería y más. Solo mencione este código al reservar su cita o muestre este correo al dejar su vehículo.\n\nComo suscriptor, también recibirá:\n• Acceso anticipado a ofertas de llantas de temporada\n• Recordatorios y consejos de mantenimiento\n• Descuentos exclusivos para suscriptores','2026-02-27 17:31:15'),(55,'email_tpl_subscriber_welcome_button','Book Your Free Inspection','Reserve su inspección gratuita','2026-02-27 17:31:15'),(56,'email_tpl_subscriber_welcome_footer','Oregon Tires Auto Care | 8536 SE 82nd Ave, Portland, OR 97266 | (503) 367-9714','Oregon Tires Auto Care | 8536 SE 82nd Ave, Portland, OR 97266 | (503) 367-9714','2026-02-27 17:31:15'),(62,'google_reviews_last_fetched','2026-03-18 06:00:07','','2026-03-18 06:00:07'),(84,'email_tpl_assignment_customer_subject','Your Appointment Has Been Assigned','Su Cita Ha Sido Asignada','2026-03-12 23:23:18'),(85,'email_tpl_assignment_customer_greeting','Hello, {{name}}!','¡Hola, {{name}}!','2026-03-12 23:23:18'),(86,'email_tpl_assignment_customer_body','Your <strong>{{service}}</strong> appointment on <strong>{{date}}</strong> at <strong>{{time}}</strong> has been assigned to <strong>{{employee_name}}</strong>.{{task_line}}<br><br>Reference: <strong>{{reference_number}}</strong>','Su cita de <strong>{{service}}</strong> el <strong>{{date}}</strong> a las <strong>{{time}}</strong> ha sido asignada a <strong>{{employee_name}}</strong>.{{task_line}}<br><br>Referencia: <strong>{{reference_number}}</strong>','2026-03-12 23:23:18'),(87,'email_tpl_assignment_customer_button','View Appointment Status','Ver Estado de Cita','2026-03-12 23:23:18'),(88,'email_tpl_assignment_customer_footer','If you have any questions, please call us at <strong>(503) 206-5923</strong> or reply to this email.','Si tiene alguna pregunta, llámenos al <strong>(503) 206-5923</strong> o responda a este correo.','2026-03-12 23:23:18'),(89,'email_tpl_assignment_employee_subject','New Assignment: {{service}} on {{date}}','Nueva Asignación: