  `google_review_id` varchar(255) DEFAULT NULL,
  `customer_name` varchar(200) NOT NULL,
  `author_photo_url` varchar(500) DEFAULT NULL,
  `google_published_at` datetime DEFAULT NULL,
  `rating` tinyint(3) unsigned NOT NULL DEFAULT 5,
  `review_text_en` text NOT NULL,
  `review_text_es` text NOT NULL DEFAULT '',
  `is_active` tinyint(1) DEFAULT 1,
  `show_on_homepage` tinyint(1) NOT NULL DEFAULT 0,
  `sort_order` int(11) DEFAULT 0,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_google_review_id` (`google_review_id`),
  KEY `idx_active` (`is_active`,`sort_order`)
) ENGINE=InnoDB AUTO_INCREMENT=178 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
